qry:select.qry:xquery:
	for $r in sql('
	SELECT TTA04_HORARIOSPERS.oi_horariopers,			
	TTA04_HORARIOSPERS.oi_personal_emp,
	TTA04_HORARIOSPERS.oi_horario,
	TTA04_HORARIOSPERS.f_fechaInicio,
	TTA04_HORARIOSPERS.f_fechaFin,
	TTA04_HORARIOSPERS.c_estado,
	ORG02_ESTRUC_PERS.oi_estructura,
	PER02_PERSONAL_EMP.e_numero_legajo,
	PER01_PERSONAL.d_ape_y_nom
	FROM TTA04_HORARIOSPERS, TTA02_HORARIOS,
	TTA04_PERSONAL, PER02_PERSONAL_EMP,
	PER01_PERSONAL, ORG02_ESTRUC_PERS
	JOIN TTA04_HORARIOSPERS.oi_horario INNER TTA02_HORARIOS.oi_horario,
	TTA04_HORARIOSPERS.oi_personal_emp INNER TTA04_PERSONAL.oi_personal_emp,
	TTA04_PERSONAL.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp,
	PER01_PERSONAL.oi_personal INNER PER02_PERSONAL_EMP.oi_personal,
	ORG02_ESTRUC_PERS.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp					
	WHERE ORG02_ESTRUC_PERS.oi_clase_org in ({%=string(#ORGANIGRAMAS:CLASES/CLASE/@oi_clase_org)%})
	{%? (#FILTRO:@f_desde != '') 
		{% AND TTA04_HORARIOSPERS.f_fechaInicio >= {DateTime(#FILTRO:@f_desde)} 					 
		%} 
		{%  %}   
	%}
	{%? (#FILTRO:@f_hasta != '') 
		{% AND TTA04_HORARIOSPERS.f_fechaInicio <= {DateTime(#FILTRO:@f_hasta)} 					 
		%} 
		{%  %}   
	%}
  {%? (#FILTRO:@oi_empresa!='') 
		{% AND PER02_PERSONAL_EMP.oi_empresa={#FILTRO:@oi_empresa} %} 
		{% %} 
	%}			
	{%? (#FILTRO:@c_estado!='') 
		{% AND TTA04_HORARIOSPERS.c_estado={#FILTRO:@c_estado} %} 
		{% %} 
	%}		   
  {%? (string(#FILTRO:ESTRUCTURAS/ESTRUCTURA/@id)!='') 
		{% AND ORG02_ESTRUC_PERS.oi_estructura in ({%=string(#FILTRO:ESTRUCTURAS/ESTRUCTURA/@id)%}) %} 
		{%  %} 
	%}
	{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') 
		{% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id)%}) %} 
		{%  %} 
	%}
	{%? (string(#FILTRO:HORARIOS/HORARIO/@id)!='') 
		{% AND TTA02_HORARIOS.oi_horario in ({%=string(#FILTRO:HORARIOS/HORARIO/@id)%}) %} 
		{%  %} 
	%}			   
	ORDER BY oi_estructura ASC, e_numero_legajo ASC 
')/ROWS/ROW
